INSERT INTO `kphis_extra`.`report_template` (`template_id`, `template_name`, `title`, `content`, `statement`, `statement_params`, `info`, `disabled`, `create_user`, `create_datetime`, `update_user`, `update_datetime`, `version`) VALUES
	(1, 'lab-v2', 'LAB REPORT V2', '= TEST LAB REPORT ', "SELECT * FROM __HOSXP__.ipt WHERE hn='__HN__' AND dchtype='__DCHTYPE__';", '__HN__|__DCHTYPE__', 'This is tester report', 1, 'admin', '2024-11-11 11:11:11', 'admin', '2024-11-11 11:11:11', 1),
    (2, 'lab-v3', 'LAB REPORT V3', '= TEST LAB REPORT', NULL, NULL, NULL, 0, 'user', '2024-11-11 11:11:11', 'admin', '2024-11-11 11:11:11', 1),
    (3, 'lab-v4', 'LAB REPORT V4', '= TEST LAB REPORT', NULL, NULL, NULL, NULL, 'admin', '2024-11-11 11:11:11', 'user', '2024-11-11 11:11:11', 1),
    (4, 'lab_alt', 'Lab', '#import "customs/config.typ": an-len, hospital-name\n#import "templates/utils.typ": api, get_patient_main, date_th, time_th\n// PRELUDE\n#let data = json("data.json")\n#assert(data.id != none, message:"no \'id\' in data")\n#let is_ipd = data.id.len() == an-len\n#let pt = data.at("patient", default: none)\n#if pt == none { pt = get_patient_main(data.id) }\n#let labs = data.at("lab", default: none)\n#if labs == none {labs = json(api + "lab/head?vn=" + data.id)}\n#let logo = if labs.len() > 0 [#image("/statics/picture/MOPH.svg",width:40pt)]\n// PREPARED FUNCTIONS\n#let label_note(l,n) = [#text(weight:700,l) #n]\n#let gline() = grid.hline(start:0,stroke:.5pt)\n#let render_gr(gr) = (grid.cell(colspan:5,strong[#gr.lab_items_group_name]),..gr.lab_items.filter(item => item.lab_order_result != none and item.lab_order_result != "").map(item => (\n  [],[#item.lab_items_name_ref],[#item.lab_order_result],[#item.lab_items_unit],[#item.lab_items_normal_value_ref]\n)).flatten())\n#let render(lab) = rect(stroke:.5pt,[\n  #grid(columns: (50pt,1fr,50pt),align(center,logo),align(center+horizon,[#strong[#hospital-name]#linebreak()#strong[#lab.form_name]#linebreak()กลุ่มงานเทคนิคการแพทย์]),[])#v(-8pt)\n  #label_note([NAME : ],[#pt.pname #pt.fname #pt.lname]) #label_note([SEX : ],pt.sex_name) #label_note([AGE : ],[#pt.age_y ปี #pt.age_m เดือน]) #label_note([HN : ],pt.hn) #label_note([#if is_ipd [AN] else [VN] : ],data.id) #label_note([จุดที่สั่ง : ],lab.department)#v(-8pt)\n  #grid(columns:(30pt,1fr,1fr,1fr,1fr),inset:3pt,\n    gline(),\n    strong[TEST],strong[NAME],strong[RESULT],strong[UNIT],strong[NORMAL RANGES],\n    gline(),\n    ..lab.lab_items_group.map(gr => render_gr(gr)).flatten(),\n    gline(),\n  )#v(-8pt)\n  #grid(columns:(170pt,80pt,1fr),par(leading:5pt,[\n    #label_note([Ordered Date : ],[#date_th(lab.order_date) #time_th(lab.order_time)])\\\n    #label_note([Received Date : ],[#date_th(lab.receive_date) #time_th(lab.receive_time)])\\\n    #label_note([Reported Date : ],[#date_th(lab.report_date) #time_th(lab.report_time)])\n  ]),par(leading:5pt,[L = Low#linebreak()H = High#linebreak()R = Repeated]),[\n    #label_note([Reported by : ],lab.reporter_name)\\\n    #label_note([Approved by : ],lab.approve_staff)\n  ])\n  #align(center,[\\*THE ABOVE RESULT REFLECTS THE ANALYSIS ONLY OF THE SAMPLE, IN ITS CONDITION RECEIVED\\*])\n])\n// RENDER\n#set text(font:"TH Sarabun New",size:12pt)\n#set page(paper:"a4",margin:1cm)\n#if labs.len() > 0 {\n  for lab in labs {render(lab)}\n}', NULL, 'id^__XX__', 'Default lab report without lab contact info\n\nNo SQL\nid: VN or AN', 0, 'marisada', '2025-12-10 17:00:38', 'marisada', '2026-01-17 16:34:20', 3),
    (5, 'demo', 'As Demo', '== START TEST #datetime.today().display()\n#import "@preview/cetz:0.5.2"\n#place(dx: 127.5pt, dy: 320pt, cetz.canvas({\n  import cetz.draw: *\n  circle((0,0), radius: 6.2, fill: rgb("#FFFDDD"), stroke: none)\n}))\n#place(bottom + right, image(width: 300pt, "statics/picture/krut.svg"))\n#let data = json("data.json")\n#assert(data.hosp != none, message: "no \'hosp\' data")\n#let xhr = data.at("xhr", default: json("api/search/box/hosp-text/" + data.hosp))\n#let hospital = text(24pt, if xhr.len() > 0 [รพ.#xhr.at(0).hospname] else [ไม่พบสถานบริการ])\n#let weather = "windy"\n#let forecast(w,hos) = block[\n    #box(square(\n        width: 2cm,\n        inset: 8pt,\n        fill: if w == "sunny" { yellow } else { aqua },\n        align(bottom + right, strong(w)),\n    ))\n    #h(6pt)\n    #set text(24pt, baseline: -8pt)\n    #hos\n]\n#forecast(weather,hospital)\n#set text(18pt)\n== มีเจ้าหน้าที่ ฉลองวันเกิดในเดือนนี้ ได้แก่\n#if data.data.len() > 0 {\n    for person in data.data [\n        - #person.opduser_name อายุ #person.age ปี\n    ]\n} else [- ไม่มีข้อมูล]', 'SELECT d.`code`,d.`name` AS doctor_name,d.birth_date,TIMESTAMPDIFF(YEAR, d.birth_date, CURDATE()) AS age,u.`name` AS opduser_name,u.entryposition,c.theme,c.wide_screen,\n    (SELECT COUNT(loginname) FROM __HOSXP__.opduser WHERE doctorcode=d.code) AS count_user\nFROM `__HOSXP__`.doctor d\n    LEFT JOIN __HOSXP__.opduser u ON u.doctorcode = d.code\n    LEFT JOIN __KPHIS_EXTRA__.user_config c ON c.loginname=u.loginname\n-- Who has a birthday this month ?\nWHERE d.active = \'Y\' AND d.code <> ? AND MONTH(d.birth_date) = MONTH(CURDATE())\nORDER BY age DESC\nLIMIT 50;', 'hosp^Hospital code^value|code^Doctor code^str', 'สำหรับการทดสอบ\n\nสำเนามาจาก Demo ที่ได้สร้างไว้\n\nข้อมูลที่ต้องการ\n1. hosp: ชื่อหรือรหัสสถานพยาบาล (ระบบจะใช้ชื่อแรกที่ค้นพบ)\n2. code: รหัส doctorcode ของเจ้าหน้าที่', 0, 'marisada', '2025-12-06 22:09:00', 'marisada', '2025-12-07 15:52:28', 9);